head.script:
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.gRow = "";
    scwin.sRegId = "";  //새로입력한 사번사용가능여부, Y:중복첵크 사용가능, N:사용불가(중복) "":첵크안했음
    scwin.sCmd = "";    //C:신규  U:수정  R:조회
    scwin.gDate = "";   //적용일자 체크용
    scwin.memInfo = $c.data.getMemInfo();

    //공통코드 조회
    const codeOptions = [
        { grpCd: "OP315", compID: "lc_occptypeClsCd" },
        { grpCd: "OP316", compID: "lc_wrkPlClsCd" }
    ];
    $c.data.setCommonCode(codeOptions, function () {
        scwin.f_defaultValue();
    });

    //제어
    $c.gus.cfDisableKeyData();
    tbl_info.setDisabled(true);
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Create, btn_Modify, btn_Save, btn_Cancel]);
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    ed_dept_01.setValue(scwin.memInfo.loUpperLobranCd);
    ed_dept_02.setValue(co_lc_srchJoblevel.getText());

    btn_occpgrdCd.setDisabled(true);
}

//-------------------------------------------------------------------------
// 화면 open시 초기 데이타 setting
// 추후 수정
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    const dcoptions = {
        baseNode: "list",
        repeatNode: "map",
        saveRemovedData: "true"
    };

    //점소 조회
    let sbmLobranCd = {
        id: "sbm_lobranCd",
        action: "/ds.co.RetreiveLoBranCMD.do"
    };
    $c.sbm.executeDynamic(sbmLobranCd).then((e) => {
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            return;
        }

        $c.data.createDataList("ds_lobranCd", ["lobranCd", "lobranNm"], ["text", "text"], dcoptions);
        ds_lobranCd.setJSON(e.responseJSON.GAUCE);
        co_lc_srchJoblevel.setNodeSet("data:ds_lobranCd", "lobranNm", "lobranCd");

        co_lc_srchJoblevel.setValue(scwin.memInfo.loUpperLobranCd);
        co_lc_srchJoblevel.focus();
    })

    //상세직종 조회
    dma_commSearch.set("lobranCd", "OP161");
    dma_commSearch.set("occptypeCd", "01");

    let sbmOccptypeCd = {
        id: "sbm_occptypeCd",
        action: "/ds.co.RetreiveLubCMD.do",
    };
    $c.sbm.executeDynamic(sbmOccptypeCd, dma_commSearch.getJSON()).then((e) => {
        if (e.responseJSON.resultDataSet[0].Code < 0) return;

        $c.data.createDataList("ds_occptypeCd", ["cd", "cdNm"], ["text", "text"], dcoptions);
        ds_occptypeCd.setJSON(e.responseJSON.GAUCE);
        lc_dtlOccptypeCd.setNodeSet("data:ds_occptypeCd", "cdNm", "cd");
        lc_dtlOccptype.setNodeSet("data:ds_occptypeCd", "cdNm", "cd");
    })
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search);
    co_lc_srchJoblevel.setValue(scwin.memInfo.loUpperLobranCd);
    co_lc_srchJoblevel.focus();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (ed_dept_01.getValue() != "" && ed_dept_02.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사업부서"]);
        return;
    }

    ds_emp.removeAll();
    let e = await $c.sbm.execute(sbm_retrieve);
    await scwin.sbm_retrieve_submitdone(e);

    //제어
    tbl_info.setDisabled(true);
    $c.gus.cfDisableKeyData();
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Save, btn_Cancel]);

    if (dma_retrieve.get("lobranCd") == "4AA") {
        $c.gus.cfEnableBtnOnly([btn_WagePeak, btn_Create, btn_Modify]);
    }

    scwin.sCmd = "R";
    gr_emp.setDisabled("grid", false);
};

//-------------------------------------------------------------------------
// 공통 팝업 호출
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        await scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        await scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1: //조회조건의 부서
            var lobranCd = co_lc_srchJoblevel.getValue();
            udc_dept_01.cfCommonPopUp(scwin.callBackDept, pCode, pName, pClose, null, null, null, null, lobranCd, null, null, null, null);
            break;

        case 2:  //조회조건의 작업장
            var lobranCd = co_lc_srchJoblevel.getValue();
            var paramList = "," + lobranCd + ",7";
            udc_works_01.cfCommonPopUp(scwin.callBackWorks, pCode, pName, pClose, null, null, null, null, paramList, null, null, null, null);
            break;

        case 3:  //Detail의 작업장
            var lobranCd = co_lc_srchJoblevel.getValue();
            var paramList = "," + lobranCd + ",7";
            udc_wrkPlCd.cfCommonPopUp(scwin.callBackWrkPl, pCode, pName, pClose, null, null, null, null, paramList, null, null, null, null);
            break;

        case 4:  //조회 조건의 사원
            var lodeptCd = "";
            if (ed_dept_01.getValue() != "" && ed_dept_02.getValue() == "") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사업부서"]);
                ed_dept_02.focus();
                return;
            }

            if (ed_dept_01.getValue() != "") {
                lodeptCd = ed_dept_01.getValue();
            }
            udc_emp_01.cfCommonPopUp(scwin.callBackEmp, pCode, pName, pClose, null, null, null, null, lodeptCd, null, null, null, null);
            break;

        case 5: //Detail의 부서
            var lobranCd = co_lc_srchJoblevel.getValue();
            udc_lodeptCd.cfCommonPopUp(scwin.callBackOpDept, pCode, pName, pClose, null, null, null, null, null, null, null, null, null);
            break;

        case 6: //직급
            udc_occpgrdCd.cfCommonPopUp(scwin.callBackOccp, pCode, pName, pClose, null, null, null, null, null, null, null, null, null);
            break;


        case 7:  //Detail의 소속업체
            udc_copCoClntNo.cfCommonPopUp(scwin.callBackClnt, pCode, pName, pClose, null, null, null, null, null, "420", null, null, null, null, null, "소속업체,소속코드,소속명");
            break;

        default:
            return;
    }
}

scwin.callBackDept = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_dept_01, ed_dept_02);
}

scwin.callBackWorks = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_works_01, ed_works_02);
}

scwin.callBackWrkPl = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_wrkPlCd, ed_wrkPlNm);
}

scwin.callBackEmp = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_emp_01, ed_emp_02);
}

scwin.callBackOpDept = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_lodeptCd, ed_lodeptNm);
}

scwin.callBackOccp = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_occpgrdCd, ed_occpgrdNm);
}

scwin.callBackClnt = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_copCoClntNo, ed_copCoClntNm);
}

//-------------------------------------------------------------------------
// 임금피크제
//-------------------------------------------------------------------------
scwin.f_wagePeak = function () {
    let url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_02_03b.xml";
    var opts = {
        id: "popupWagePeack"
        , popupName: "임금피크제 등록"
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "임금피크제 등록"  //Layer pop
        , width: 700
        , height: 500
    };

    let data = {
        empNo: ed_staffNo.getValue()
        , empNm: ed_staffNm.getValue()
    }

    $c.win.openPopup(url, opts, data);
}

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    let row = ds_emp.insertRow();
    scwin.gRow = ds_emp.getRowPosition();
    gr_emp.setFocusedCell(row, 0);
    ds_emp.setCellData(row, "occptypeCd", "01");

    tbl_info.setDisabled(false);
    $c.gus.cfEnableKeyData();
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Create, btn_Modify]);

    gr_emp.setDisabled("grid", true);
    scwin.sCmd = "C";
    scwin.f_displayFunction(scwin.sCmd);
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {
    if (ds_emp.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);
        return;
    }

    //제어
    scwin.gRow = ds_emp.getRowPosition();
    $c.gus.cfEnableKeyData();
    tbl_info.setDisabled(false);
    $c.gus.cfEnableObj(ed_staffNo, false);
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Create, btn_Modify]);

    scwin.gDate = ed_adptStDt.getValue();
    ed_adptStDt.setValue("");
    if (dma_retrieve.get("lobranCd") == "4AA") {
        $c.gus.cfDisableBtnOnly([btn_WagePeak]);
    }

    gr_emp.setDisabled("grid", true);
    scwin.sCmd = "U";
    scwin.f_displayFunction(scwin.sCmd);
}

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    tbl_info.setDisabled(true);
    gr_emp.setDisabled("grid", false);

    let rowIdx = ds_emp.getModifiedIndex();
    for (let row = 0; row < rowIdx.length; row++) {
        let row = rowIdx[0]
        let sts = ds_emp.getRowStatus(row);

        if (sts == "C") {
            ds_emp.removeRow(row);
            gr_emp.setFocusedCell(scwin.gRow, 0);
        } else if (sts == "U" || sts == "D") {
            ds_emp.undoRow(row);
        }
    }
    scwin.f_displayFunction();

    $c.gus.cfDisableKeyData();
    $c.gus.cfEnableBtnOnly([btn_WagePeak, btn_Save, btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Cancel, btn_Save]);
    if (dma_retrieve.get("lobranCd") == "4AA") {
        $c.gus.cfEnableBtnOnly([btn_WagePeak]);
    }
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    //변경한 데이터가 있는지 체크한다. 
    if (ds_emp.getModifiedData().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["정규기능직원수정"]);
        return;
    }

    if (scwin.sCmd == "C") {
        if (scwin.sRegId == "N") {
            await $c.win.alert("이미 등록되어있는 사번입니다.");
            return;
        } else if (scwin.sRegId == "") {
            await $c.win.alert("사원번호 중복확인을 해주시기 바랍니다.");
            return;
        }
    }

    // 사번
    if (!await $c.gus.cfValidate(ed_staffNo)) {
        return;
    }

    if (ed_staffNm.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사원명"]);
        ed_staffNm.focus();
        return;
    }

    if (ed_occpgrdCd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["직급"]);
        ed_occpgrdCd.focus();
        return;
    }

    if (ed_occpgrdNm.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["직급"]);
        ed_occpgrdNm.focus();
        return;
    }

    if (lc_dtlOccptype.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["상세직종"]);
        lc_dtlOccptype.focus();
        return;
    }

    if (ed_lodeptCd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사업부서"]);
        ed_lodeptCd.focus();
        return;
    }

    if (ed_lodeptNm.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사업부서"]);
        ed_lodeptNm.focus();
        return;
    }

    if (ed_entDt.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["입사일자"]);
        ed_entDt.focus();
        return;
    }

    if (ed_adptStDt.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["적용일자"]);
        ed_adptStDt.focus();
        return;
    }

    if (ed_retireDt.getValue() != "") {
        if (!await $c.gus.cfValidate(ed_retireDt)) {
            return;
        }

        if (!$c.gus.cfIsAfterDate(ed_entDt.getValue(), ed_retireDt.getValue(), false)) {
            $c.gus.f_cfAlertMsg("퇴사일자는 입사일자 이후이어야 합니다.");
            ed_retireDt.focus();
            return;
        }
    }

    if (scwin.sCmd == "U") {
        if (ed_adptStDt.getValue() < scwin.gDate) {
            $c.gus.f_cfAlertMsg("적용일자는 이전 적용일자 [" + scwin.gDate + "] 이후 날짜로 입력하셔야 합니다.");
            return;
        }
    }

    let conf = await $c.win.confirm(MSG_CM_CRM_001);
    if (conf) {
        let rowStatus = gr_emp.getFocusedRowStatus();
        let e = await $c.sbm.execute(sbm_saveEmp);
        await scwin.sbm_saveEmp_submitdone(e, rowStatus === "C");
    } else {
        scwin.f_Cancel();
        return;
    }

    //제어
    tbl_info.setDisabled(true);
    $c.gus.cfDisableKeyData();
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Save, btn_Cancel]);

    if (dma_retrieve.get("lobranCd") == "4AA") {
        $c.gus.cfEnableBtnOnly([btn_WagePeak]);
    }

    gr_emp.setDisabled("grid", false);
};

//-------------------------------------------------------------------------
// 사번 중복첵크
//-------------------------------------------------------------------------
scwin.f_dupYn = async function () {
    if (!await $c.gus.cfValidate(ed_staffNo)) {
        return;
    }

    dma_retrieve.set("employeeNumber", ed_staffNo.getValue());
    ds_dupYn.removeAll();
    $c.sbm.execute(sbm_dupYn);
}

scwin.f_displayFormatterSsn = function (data) {
    if ($c.util.isEmpty(data)) {
        return "";
    }
    if (scwin.sCmd == "R") {
        return data.substr(0, 6) + "-*******";
    } else {
        return data.substr(0, 6) + "-";
    }
}

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//조회 성공
scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return;
    }

    var rowCnt = ds_emp.getRowCount();
    spn_totalRow.setValue(rowCnt);
    gr_emp.setFocusedCell(0, 0);
    scwin.f_displayFunction();

    if (rowCnt == 0) {
        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    }
};

//사번 중복 조회
scwin.sbm_dupYn_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return;
    }

    //L792
    if (ds_dupYn.getRowCount() > 0) {
        if (ds_dupYn.getCellData(0, "dupYn") == "Y") {
            await $c.win.alert("이미 등록된 사번입니다.");
            scwin.sRegId = "N";
        } else {
            await $c.win.alert("등록 가능한 사번입니다.");
            scwin.sRegId = "Y";
        }
    }
};

//저장
scwin.sbm_saveEmp_submitdone = function (e, isCreate = false) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return;
    }

    ds_emp.reform();
    if (isCreate) {
        ed_ssn.setEditFormat("XXXXXX-*******");
        ds_emp.setIgnoreStatus("ssn1", false);
        let ssn = ed_ssn.getValue();
        ds_emp.setCellData(gr_emp.getFocusedRowIndex(), "ssn1", ssn.substring(0, 6) + "*******");
    }
    scwin.sRegId = "";
    $c.gus.cfDisableKeyData();
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify, btn_Save, btn_Cancel]);
    $c.gus.cfDisableBtnOnly([btn_WagePeak, btn_Save, btn_Cancel]);
    if (dma_retrieve.get("lobranCd") == "4AA") {
        $c.gus.cfEnableBtnOnly([btn_WagePeak]);
    }

    gr_emp.setDisabled("grid", false);
};
/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//조회영역 점소 blur
scwin.co_lc_srchJoblevel_onchange = function (info) {
    ed_dept_01.setValue(co_lc_srchJoblevel.getValue());
    ed_dept_02.setValue(co_lc_srchJoblevel.getText(true));
};

//조회영역 사업부서 찾기 버튼 
scwin.udc_dept_01_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(1, ed_dept_01.getValue(), ed_dept_02.getValue(), 'F', 'F');
};

scwin.udc_dept_01_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_dept_01, ed_dept_02, 1);
};

scwin.udc_dept_01_onviewchangeNameEvent = async function (info) {
    await scwin.f_chkOpenCommonPopUp(ed_dept_02, ed_dept_01, 1, false);
};

//조회영역 작업장 찾기 버튼 
scwin.udc_works_01_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(2, ed_works_01.getValue(), ed_works_02.getValue(), 'F', 'F');
};

scwin.udc_works_01_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_works_01, ed_works_02, 2);
};

scwin.udc_works_01_onviewchangeNameEvent = async function (info) {
    await scwin.f_chkOpenCommonPopUp(ed_works_02, ed_works_01, 2, false);
};

//조회영역 사원 찾기 버튼 
scwin.udc_emp_01_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(4, ed_emp_01.getValue(), ed_emp_02.getValue(), 'F', 'F');
};

scwin.udc_emp_01_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_emp_01, ed_emp_02, 4);
};

scwin.udc_emp_01_onviewchangeNameEvent = async function (info) {
    await scwin.f_chkOpenCommonPopUp(ed_emp_02, ed_emp_01, 4, false);
};

//조회조건 clear 버튼
scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

//조회 버튼
scwin.btn_search_onclick = async function (e) {
    await scwin.f_Retrieve();
};

//사번 중복 버튼
scwin.btn_dupYn_onclick = function (e) {
    scwin.f_dupYn();
};

//상세 직급 찾기 버튼 
scwin.udc_occpgrdCd_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(6, ed_occpgrdCd.getValue(), ed_occpgrdNm.getValue(), 'F', 'F');
};

scwin.udc_occpgrdCd_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_occpgrdCd, ed_occpgrdNm, 6);
};

scwin.udc_occpgrdCd_onviewchangeNameEvent = async function (info) {
    await scwin.f_chkOpenCommonPopUp(ed_occpgrdNm, ed_occpgrdCd, 6, false);
};

//상세 사업부서 찾기 버튼
scwin.udc_lodeptCd_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(5, ed_lodeptCd.getValue(), ed_lodeptNm.getValue(), 'F', 'F')
};

scwin.udc_lodeptCd_onblurCodeEvent = async function (e) {
